for (const item of $input.all()) {
  const rawStr = item.json.full_records;

  function parseCustomFormat(str) {
    // Remove the outer curly braces
    let content = str.trim().replace(/^\{/, '').replace(/\}$/, '');
    let result = {};

    // Regex to find key=value pairs, accounting for nested { } blocks
    // This looks for a key followed by =, then captures everything until the next 
    // top-level comma or the end of the string
    const pairRegex = /([^,=\s]+)=({[^{}]*}|\[[^\[\]]*\]|[^,}]*)/g;
    let match;

    while ((match = pairRegex.exec(content)) !== null) {
      let key = match[1].trim();
      let value = match[2].trim();

      // Handle Nested Objects recursively
      if (value.startsWith('{')) {
        value = parseCustomFormat(value);
      } 
      // Handle Arrays [val]
      else if (value.startsWith('[')) {
        value = value.replace(/[\[\]]/g, '').split(',').map(v => v.trim());
      }
      // Handle Numbers
      else if (!isNaN(value) && value !== '') {
        value = Number(value);
      }
      // Clean up string values (remove any trailing/leading accidental quotes)
      else {
        value = value.replace(/^"(.*)"$/, '$1');
      }

      result[key] = value;
    }
    return result;
  }

  try {
    item.json.full_records = parseCustomFormat(rawStr);
  } catch (e) {
    item.json.error = "Parsing failed: " + e.message;
  }
}

return $input.all();

return items.map(item => {
  const text = item.json.body;
  const key = `"full_record"`;
  const results = [];
  let pos = 0;

  while (true) {
    // Find next occurrence of "full_record"
    const idx = text.indexOf(key, pos);
    if (idx === -1) break;

    // Find start of the object
    const start = text.indexOf('{', idx + key.length);
    if (start === -1) break;

    let depth = 0;
    let end = start;

    // Walk to find matching closing brace
    for (let i = start; i < text.length; i++) {
      if (text[i] === '{') depth++;
      if (text[i] === '}') depth--;
      if (depth === 0) {
        end = i;
        break;
      }
    }

    // Extract the substring
    const fullRecordStr = text.substring(start, end + 1);
    results.push(fullRecordStr);

    // Move past current end so we find next
    pos = end + 1;
  }

  return {
    json: {
      full_records: results
    }
  };
});

const allItems = [];

for (const item of items) {
  allItems.push(item.json.data);
}

return [{
  json: {
    combined: JSON.stringify(allItems)
  }
}];
